#!/usr/bin/env python3
import sys
import xml.etree.ElementTree as ET


def parse_manifest(path: str) -> list[str]:
    root = ET.parse(path).getroot()
    return [node.get('name', '') for node in root.findall('.//service')]


if __name__ == '__main__':
    for service in parse_manifest(sys.argv[1]):
        print(service)
